/**
 * @summary List AI replication jobs
 */
export const getListReplicationJobsUrl = (
  params: ListReplicationJobsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/ai/jobs?${stringifiedParams}`
    : `/api/ai/jobs`;
};

export const listReplicationJobs = async (
  params: ListReplicationJobsParams,
  options?: RequestInit,
): Promise<ReplicationJob[]> => {
  return customFetch<ReplicationJob[]>(getListReplicationJobsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListReplicationJobsQueryKey = (
  params?: ListReplicationJobsParams,
) => {
  return [`/api/ai/jobs`, ...(params ? [params] : [])] as const;
};

export const getListReplicationJobsQueryOptions = <
  TData = Awaited<ReturnType<typeof listReplicationJobs>>,
  TError = ErrorType<unknown>,
>(
  params: ListReplicationJobsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listReplicationJobs>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListReplicationJobsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listReplicationJobs>>
  > = ({ signal }) =>
    listReplicationJobs(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listReplicationJobs>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListReplicationJobsQueryResult = NonNullable<
  Awaited<ReturnType<typeof listReplicationJobs>>
>;
export type ListReplicationJobsQueryError = ErrorType<unknown>;

/**
 * @summary List AI replication jobs
 */

